54	// Vectorized addition for float32 (https://docs.nvidia.com/cuda/parallel-thread-execution/#floating-point-instructions-add)
55	CUTE_DEVICE
56	float2 float2_add(const float2 &a, const float2 &b) {
57	    float2 c;
58	    asm volatile(
59	        "add.f32x2 %0, %1, %2;\n"
60	        : "=l"(reinterpret_cast<uint64_t&>(c))
61	        : "l"(reinterpret_cast<uint64_t const&>(a)),
62	          "l"(reinterpret_cast<uint64_t const&>(b))
63	    );
64	    return c;
65	}
