79	// Vectorized fused addition-multiplication for float32 (https://docs.nvidia.com/cuda/parallel-thread-execution/#floating-point-instructions-fma)
80	CUTE_DEVICE
81	float2 float2_fma(const float2 &a, const float2 &b, const float2 &c) {
82	    // return a*b+c
83	    float2 d;
84	    asm volatile(
85	        "fma.rn.f32x2 %0, %1, %2, %3;\n"
86	        : "=l"(reinterpret_cast<uint64_t&>(d))
87	        : "l"(reinterpret_cast<uint64_t const&>(a)),
88	          "l"(reinterpret_cast<uint64_t const&>(b)),
89	          "l"(reinterpret_cast<uint64_t const&>(c)));
90	    return d;
91	}
