146	// Get the result of a CLC query (https://docs.nvidia.com/cuda/parallel-thread-execution/#parallel-synchronization-and-communication-instructions-clusterlaunchcontrol-query-cancel)
147	// In this function, we separate get_first_ctaid::x/y/z and hope PTXAS's dead code elimination can remove unnecessary instructions
148	template<bool USE_LD_ACQUIRE>
149	CUTE_DEVICE
150	CLCResult get_clc_query_response(CLCResponseObj &response_obj) {
151	    uint32_t response_addr = cute::cast_smem_ptr_to_uint(&response_obj);
152	    CLCResult result;
153	    #define EMIT_ASM(LD_MODIFIER)                                                                   \
154	        asm volatile(                                                                               \
155	            "{\n"                                                                                   \
156	            ".reg .pred p1;\n\t"                                                                    \
157	            ".reg .b128 clc_result;\n\t"                                                            \
158	            "ld" LD_MODIFIER ".shared.b128 clc_result, [%4];\n\t"                                   \
159	            "clusterlaunchcontrol.query_cancel.is_canceled.pred.b128 p1, clc_result;\n\t"           \
160	            "selp.u32 %3, 1, 0, p1;\n\t"                                                            \
161	            "@p1 clusterlaunchcontrol.query_cancel.get_first_ctaid::x.b32.b128 %0, clc_result;\n\t" \
162	            "@p1 clusterlaunchcontrol.query_cancel.get_first_ctaid::y.b32.b128 %1, clc_result;\n\t" \
163	            "@p1 clusterlaunchcontrol.query_cancel.get_first_ctaid::z.b32.b128 %2, clc_result;\n\t" \
164	            "}\n"                                                                                   \
165	            : "=r"(result.x), "=r"(result.y), "=r"(result.z), "=r"(result.is_valid)                 \
166	            : "r"(response_addr)                                                                    \
167	            : "memory"                                                                              \
168	        );
169	    if constexpr (USE_LD_ACQUIRE) {
170	        EMIT_ASM(".acquire.cta");
171	    } else {
172	        EMIT_ASM("");
173	    }
174	    return result;
175	}
