9	// Perform SS UTCMMA
10	// sA and sB should be shared memory tensors (i.e. make_tensor(make_shared_ptr(XXX), XXX)) while tC_frag should be tmem fragment
11	template<
12	    typename TiledMMA,
13	    typename TensorA,
14	    typename TensorB,
15	    typename TensorFragC
16	>
17	CUTE_DEVICE
18	void utcmma_ss(
19	    TiledMMA &tiled_mma,
20	    TensorA sA,
21	    TensorB sB,
22	    TensorFragC tC_frag,
23	    bool clear_accum
24	) {
25	    using namespace cute;
26	    tiled_mma.accumulate_ = clear_accum ? UMMA::ScaleOut::Zero : UMMA::ScaleOut::One;
27	    ThrMMA thr_mma = tiled_mma.get_slice(_0{}); // Since A/B/C are already CTA-local tiles, this number does not matter
28	    auto sA_frag = thr_mma.partition_fragment_A(sA);
29	    auto sB_frag = thr_mma.partition_fragment_B(sB);
30	    static_assert(size<2>(sA_frag) == size<2>(sB_frag));
31	    static_assert(size<1>(sA_frag) == size<1>(tC_frag));
32	    static_assert(size<1>(sB_frag) == size<2>(tC_frag));
33	    CUTE_UNROLL
34	    for (int k = 0; k < size<2>(sA_frag); ++k) {
35	        cute::gemm(
36	            tiled_mma,
37	            sA_frag(_, _, k),
38	            sB_frag(_, _, k),
39	            tC_frag
40	        );
41	        tiled_mma.accumulate_ = UMMA::ScaleOut::One;
42	    }
43	}
44	
45	// Perform TS UTCMMA
46	// sB should be shared memory tensors (i.e. make_tensor(make_shared_ptr(XXX), XXX)) while tA_frag and tC_frag should be tmem fragment
47	template<
48	    typename TiledMMA,
49	    typename TensorA,
50	    typename TensorB,
51	    typename TensorFragC
52	>
53	CUTE_DEVICE
54	void utcmma_ts(
55	    TiledMMA &tiled_mma,
56	    TensorA tA_frag,
57	    TensorB sB,
58	    TensorFragC tC_frag,
59	    bool clear_accum
60	) {
61	    using namespace cute;
62	    tiled_mma.accumulate_ = clear_accum ? UMMA::ScaleOut::Zero : UMMA::ScaleOut::One;
63	    ThrMMA thr_mma = tiled_mma.get_slice(_0{}); // Since A/B/C are already CTA-local tiles, this number does not matter
64	    auto sB_frag = thr_mma.partition_fragment_B(sB);
65	    static_assert(size<2>(tA_frag) == size<2>(sB_frag));
66	    CUTE_UNROLL
67	    for (int k = 0; k < size<2>(tA_frag); ++k) {
68	        cute::gemm(
69	            tiled_mma,
70	            tA_frag(_, _, k),
71	            sB_frag(_, _, k),
72	            tC_frag
73	        );
74	        tiled_mma.accumulate_ = UMMA::ScaleOut::One;
75	    }
76	}
