78	template<int MN, int K, int SWIZZLE, typename T = bf16>
79	static constexpr auto make_umma_canonical_k_major_layout() {
80	    using namespace cute;
81	    using base_atom_type = \
82	        std::conditional_t<SWIZZLE == 0 || SWIZZLE == 16, 
83	            UMMA::Layout_K_INTER_Atom<T>,
84	            std::conditional_t<SWIZZLE == 32,
85	                UMMA::Layout_K_SW32_Atom<T>,
86	                std::conditional_t<SWIZZLE == 64,
87	                    UMMA::Layout_K_SW64_Atom<T>,
88	                    std::conditional_t<SWIZZLE == 128,
89	                        UMMA::Layout_K_SW128_Atom<T>,
90	                        void
91	                    >
92	                >
93	            >
94	        >;
95	    static_assert(!std::is_same_v<base_atom_type, void>, "Invalid SWIZZLE value");
96	    return coalesce(tile_to_shape(
97	        base_atom_type{},
98	        Shape<Int<MN>, Int<K>>{},
99	        Step<_1, _2>{}
100	    ), Shape<_1, _1>{});
101	}
